/**
 * Detect whether a parsed `.claude/settings.json` was generated by navori.
 * The marker is a top-level key `$navori` with `managed: true`. If absent,
 * the file is treated as user-owned and the engine adapter refuses to
 * overwrite it (DT-2 in spec 0002).
 */

export const NAVORI_OWNERSHIP_MARKER = "$navori";

export function isNavoriOwnedSettings(parsed: unknown): boolean {
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return false;
  const navori = (parsed as Record<string, unknown>)[NAVORI_OWNERSHIP_MARKER];
  if (!navori || typeof navori !== "object" || Array.isArray(navori)) return false;
  return (navori as Record<string, unknown>).managed === true;
}
